//go:build !linux

package utils

import "os"

// GetBlockOrFileSize returns the size of the file at path. On non-Linux
// platforms only regular files are supported; block devices are not available.
func GetBlockOrFileSize(path string) (int64, error) {
	st, err := os.Stat(path)
	if err != nil {
		return 0, err
	}
	return st.Size(), nil
}
